mapper.select:
SELECT c.*, u.name AS assign_name
FROM clue c
LEFT JOIN `user` u ON c.user_id = u.id


        AND c.name LIKE CONCAT('%', #{clueDto.name}, '%')


        AND c.phone = #{clueDto.phone}


        AND c.status = #{clueDto.status}


        AND c.user_id = #{clueDto.userId}


ORDER BY c.update_time DESC
